#include <bits/stdc++.h>
using namespace std;

const int N=310;

int n,w[N],f[N][N][2],g[N][2],sum[N];
vector<int> e[N];

void cmax(int &x,int y){
    x=max(x,y);
}

void dfs(int x,int fa){
    sum[x]=w[x];
    for(int i=0;i<=n;i++){
        f[x][i][0]=w[x]*(i+1);
        f[x][i][1]=w[x];
    }
    for(int y:e[x])
        if(y!=fa){
            dfs(y,x);
            sum[x]+=sum[y];
            memset(g,0xcf,sizeof(g));
            for(int i=0;i<=n;i++){
                cmax(g[i][0],f[x][i][0]+f[y][i+1][0]);
                cmax(g[i][0],f[x][i][0]+f[y][i][1]);
                if(i) cmax(g[i][1],f[x][i][1]+f[y][i-1][1]+sum[y]);
                else cmax(g[i][1],f[x][i][1]+f[y][1][0]);
                cmax(g[i][1],f[x][i][1]+f[y][i][0]);
            }
            for(int i=0;i<=n;i++){
                f[x][i][0]=g[i][0];
                f[x][i][1]=g[i][1];
            }
        }
}

int main(){
    scanf("%d",&n);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        e[u].push_back(v);
        e[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
        scanf("%d",&w[i]);
    memset(f,0xcf,sizeof(f));
    dfs(1,0);
    printf("%d",f[1][0][0]);
    return 0;
}
